算法思想：使用快慢指针找到链表中间位置，同时将前半部分逆置，然后比较前后两部分。

```c
int IsSymmetric(LinkList L) {
    if (L->next == NULL || L->next->next == NULL) return 1;
    LNode *slow = L->next, *fast = L->next, *prev = NULL, *temp;
    while (fast != NULL && fast->next != NULL) {
        fast = fast->next->next;
        temp = slow->next; slow->next = prev;
        prev = slow; slow = temp;
    }
    if (fast != NULL) slow = slow->next; // 奇数跳过中间
    while (prev != NULL && slow != NULL) {
        if (prev->data != slow->data) return 0;
        prev = prev->next; slow = slow->next;
    }
    return 1;
}
```
时间复杂度O(n)，空间O(1)。

